import React, { Component } from "react";
import SingleCharacterUpdate from "../controller/singleCharacterUpdate";

class UpdateCharacter extends Component {
  state = {
    docId: this.props.match.params.id,
    toUpdate: false,
  };

  render() {
    return (
      <div className="App">
        <h1>Update Page</h1>
        <SingleCharacterUpdate docId={this.state.docId} />
      </div>
    );
  }
}

export default UpdateCharacter;
