import React, { Component } from "react";
import { Button } from "react-bootstrap";
import "../App.css";
import GetCharactersService from "../controller/getCharactersService";

class Characters extends Component {
  state = {};
  render() {
    return (
      <div className="App">
        <h1>Characters</h1>
        <Button variant="outline-danger" href="/NewCharacter">
          Make a New Character
        </Button>
        <GetCharactersService />
      </div>
    );
  }
}

export default Characters;
