import React from "react";
import { Col, Row } from "react-bootstrap";
import firebase from "./firebase";

const SingleCharacterSpellsView = ({ docId }) => {
  const [spells, setSpells] = React.useState([]);

  React.useEffect(() => {
    if (spells.length !== 0) {
      return;
    }

    const fetchData = async () => {
      const db = firebase.firestore();
      const data = await db.collection("characters/" + docId + "/spells").get();
      setSpells(data.docs.map((doc) => ({ id: doc.id, ...doc.data() })));
    };
    fetchData();
    console.log(spells);
  }, []);

  return (
    <div>
      <div className="single-character-container-table">
        <h1>Spells</h1> length: {spells.length}
        {spells.map((spell) => (
          <div className="spell-card">
            <h1>{spell.name}</h1>
            <Row>
              <Col>
                <h6>Attack/Save: {spell.attackSave}</h6>
              </Col>
              <Col>
                <h6>Casting Time: {spell.castingTime}</h6>
              </Col>
              <Col>
                <h6>Level: {spell.level}</h6>
              </Col>
            </Row>
            <Row>
              <Col>
                <h6>Duration: {spell.duration}</h6>
              </Col>
              <Col>
                <h6>Range: {spell.range}</h6>
              </Col>
              <Col>
                <h6>School: {spell.school}</h6>
              </Col>
            </Row>
            <Row>
              <Col>
                <h5>Description</h5>
              </Col>
            </Row>
            <Row>
              <Col>
                <p>{spell.description}</p>
              </Col>
            </Row>
          </div>
        ))}
      </div>
    </div>
  );
};

export default SingleCharacterSpellsView;
